/**
 * 🛠️ DYNAMIC ICON LOADER & FIREWALL DIAGNOSTIC TOOL
 * Components: Logic, .map Generator, and Blame-Trace
 */

const fs = require('fs');
const path = require('path');

// 1. CONFIGURATION & FIREWALL METADATA
const CONFIG = {
    inputDir: './src/assets/icons',
    outputFile: './src/dynamicIconImports.js',
    mapFile: './src/dynamicIconImports.js.map',
    firewallRules: [
        { dest: "registry.npmjs.org", port: 443, role: "Dependency Fetching" },
        { dest: "cdn.lucide.dev", port: 443, role: "Remote Asset Sync" }
    ]
};

/**
 * 2. BLAME & DIAGNOSTIC LOGIC
 * Identifies if a build crash is a Code error or a Firewall block.
 */
function runBlameReport(error) {
    console.error("\n--- 🔎 AUTOMATION BLAME REPORT ---");
    if (error.code === 'ENOTFOUND' || error.code === 'ETIMEDOUT') {
        console.error("CRITICAL: Network Firewall Violation detected.");
        console.error(`Check Outbound Rules for: ${CONFIG.firewallRules.map(r => r.dest).join(', ')}`);
    } else if (error.code === 'ENOENT') {
        console.error("CRITICAL: File System / Mount Error. Verify local access permissions.");
    } else {
        console.error("CRITICAL: JavaScript Logic Error. Use the .map file to trace the stack.");
    }
    console.error("----------------------------------\n");
}

async function buildDynamicSystem() {
    try {
        console.log("🚀 Initializing Dynamic Import Automation...");

        if (!fs.existsSync(CONFIG.inputDir)) {
            throw { code: 'ENOENT', message: 'Input directory missing' };
        }

        const files = fs.readdirSync(CONFIG.inputDir).filter(f => f.endsWith('.svg'));
        
        // 3. GENERATE DYNAMIC CODE
        let jsCode = `/* AUTO-GENERATED BY AUTOMATOR */\n`;
        jsCode += `export const iconRegistry = {\n`;
        
        files.forEach(file => {
            const name = path.parse(file).name;
            jsCode += `  "${name}": () => import('./assets/icons/${file}'),\n`;
        });
        
        jsCode += `};\n\n//# sourceMappingURL=dynamicIconImports.js.map`;

        // Write JS
        fs.writeFileSync(CONFIG.outputFile, jsCode);

        // 4. GENERATE SOURCE MAP (.js.map)
        // This allows the browser/debugger to link minified chunks back to original SVGs
        const sourceMap = {
            version: 3,
            file: "dynamicIconImports.js",
            sources: [path.resolve(CONFIG.inputDir)],
            names: [],
            mappings: "AAAA" // Placeholder mapping for automation tracing
        };

        fs.writeFileSync(CONFIG.mapFile, JSON.stringify(sourceMap));

        console.log(`✅ Success! ${files.length} icons indexed.`);
        console.log(`📍 Map generated: ${CONFIG.mapFile}`);

    } catch (err) {
        runBlameReport(err);
        process.exit(1);
    }
}

// Execute
buildDynamicSystem();